Let me think about the Server Action approach:

```tsx
// app/admin/products/page.tsx
import { unstable_cache } from "next/cache";
import { revalidateTag } from "next/cache";
import { getAllProducts } from "@/lib/db";

// Cached data fetching function
const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ["catalog-products"],
  { tags: ["products"], revalidate: false }
);

export default async function AdminProductsPage() {
  async function syncCatalog() {
    "use server";
    // Trigger revalidation - in a real app this would also
    // trigger an async job to refresh from upstream ERP/PIM
    revalidateTag("products");
  }

  const products = await getCachedProducts();

  return (
    <div>
      <h1>Product Catalog</h1>
      <form action={syncCatalog}>
        <button type="submit">Sync latest catalog</button>
      </form>
      <table>
        {products.map(p => (
          <tr key={p.id}>
            <td>{p.name}</td>
            <td>{p.price}</td>
          </tr>
        ))}
      </table>
    </div>
  );
}
```

