export interface Product {
  id: number;
  sku: string;
  name: string;
  price: number;
  inventoryCount: number;
  status: "active" | "inactive";
  category: string;
}

export interface SyncResult {
  syncedAt: string;
  updatedCount: number;
}

// Seed data — represents the upstream product catalog (ERP/PIM).
// In production this would be a database queried by getAllProducts()
// and periodically refreshed by triggerSync().
let products: Product[] = [
  { id: 1, sku: "SKU-LAP-001", name: "Laptop Pro 16", price: 1999.99, inventoryCount: 45, status: "active", category: "Computers" },
  { id: 2, sku: "SKU-PHN-002", name: "Phone XR", price: 899.99, inventoryCount: 120, status: "active", category: "Phones" },
  { id: 3, sku: "SKU-TAB-003", name: "Tablet Air", price: 649.99, inventoryCount: 78, status: "active", category: "Tablets" },
  { id: 4, sku: "SKU-HDP-004", name: "Headphones Pro", price: 249.99, inventoryCount: 200, status: "active", category: "Audio" },
  { id: 5, sku: "SKU-WTH-005", name: "Smart Watch", price: 349.99, inventoryCount: 0, status: "inactive", category: "Wearables" },
];

let lastSyncAt = "";

export async function getAllProducts(): Promise<Product[]> {
  // Simulate database read latency
  await new Promise((resolve) => setTimeout(resolve, 200));
  return products.map((p) => ({ ...p }));
}

export function getLastSyncAt(): string {
  return lastSyncAt;
}

/**
 * Simulate fetching updated catalog data from upstream ERP/PIM.
 *
 * In production this function would:
 *  1. Enqueue an async job that batches across thousands of SKUs
 *  2. Return immediately — the admin sees stale cached data while
 *     the job processes upstream pricing / inventory / availability changes
 *  3. Call revalidateTag("products") once the job completes
 *
 * For this demo the work happens inline with a short delay so the
 * cache-invalidation flow is observable.
 */
export async function triggerSync(): Promise<SyncResult> {
  // Simulate upstream data-fetch latency
  await new Promise((resolve) => setTimeout(resolve, 150));

  const previous = [...products];

  // Apply simulated upstream changes (pricing, stock levels)
  products = products.map((p) => {
    const inventoryDelta = Math.floor(Math.random() * 10) - 2; // -2 … +7
    const priceMultiplier = 1 + (Math.random() * 0.06 - 0.03); // ±3%

    return {
      ...p,
      inventoryCount: Math.max(0, p.inventoryCount + inventoryDelta),
      price: Number((p.price * priceMultiplier).toFixed(2)),
    };
  });

  lastSyncAt = new Date().toISOString();

  const changedCount = products.filter(
    (p, i) =>
      p.price !== previous[i].price ||
      p.inventoryCount !== previous[i].inventoryCount,
  ).length;

  return { syncedAt: lastSyncAt, updatedCount: changedCount };
}

import { unstable_cache } from "next/cache";
import { getAllProducts, type Product } from "./db";

/**
 * Cached product catalog.
 *
 * Reads from the data-cache layer, tagged with "products" so that
 * a call to `revalidateTag("products")` (e.g. from a sync Server
 * Action) invalidates every view that depends on this data.
 *
 * `revalidate: false` means the cache never auto-expires — it is
 * only invalidated on demand when the admin triggers a sync, keeping
 * day-to-day browsing fast and avoiding re-querying on every request.
 */
export const getCachedProducts = unstable_cache(
  async (): Promise<Product[]> => {
    const products = await getAllProducts();
    return products;
  },
  ["catalog-products-list"],
  { tags: ["products"], revalidate: false },
);

import Link from "next/link";

export default function AdminLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <div style={{ display: "flex", minHeight: "100vh" }}>
      {/* Sidebar */}
      <nav
        style={{
          width: 240,
          borderRight: "1px solid #e5e7eb",
          padding: "24px 16px",
          display: "flex",
          flexDirection: "column",
          gap: 4,
        }}
      >
        <div
          style={{
            fontWeight: 700,
            fontSize: 18,
            marginBottom: 16,
            color: "#111827",
          }}
        >
          Admin
        </div>
        <Link
          href="/admin/products"
          style={{
            display: "block",
            padding: "8px 12px",
            borderRadius: 6,
            color: "#374151",
            textDecoration: "none",
            fontSize: 14,
          }}
        >
          Products
        </Link>
      </nav>

      {/* Main content */}
      <main style={{ flex: 1, padding: "32px 40px", backgroundColor: "#f9fafb" }}>
        {children}
      </main>
    </div>
  );
}

"use client";

import { useFormStatus } from "react-dom";

export function SyncButton() {
  const { pending } = useFormStatus();

  return (
    <button
      type="submit"
      disabled={pending}
      style={{
        padding: "10px 20px",
        backgroundColor: pending ? "#9ca3af" : "#2563eb",
        color: "#fff",
        border: "none",
        borderRadius: 6,
        cursor: pending ? "not-allowed" : "pointer",
        fontSize: 14,
        fontWeight: 500,
        display: "inline-flex",
